    64→        </div>
    65→
    66→        <!-- Empty state -->
    67→        <div v-else-if="!formattedXml" class="preview-empty">
    68→          <p>Your formatted document will appear here.</p>
    69→        </div>
    70→
    71→        <!-- Preview + badge -->
    72→        <template v-else>
    73→          <PreviewPanel
    74→            :xml-content="formattedXml"
    75→            :zoom="1"
    76→          />
    77→          <div v-if="documentType" class="document-badge">
    78→            {{ documentType === 'resume' ? 'Resume detected' : 'Cover letter detected' }} ✓
    79→          </div>
