     1→/**
     2→ * Resume / Cover Letter Render Styles
     3→ *
     4→ * Styles the custom XML elements produced by the AI pipeline:
     5→ *   <document>, <header>, <name>, <contact>, <experience>, etc.
     6→ *
     7→ * These custom elements are rendered as HTML via DOMPurify + v-html.
     8→ * The browser treats unknown elements as inline by default, so each
     9→ * element that needs block-level layout must have display set explicitly.
    10→ *
    11→ * Design system:
    12→ *   --ink:    #111  (body text)
    13→ *   --muted:  #555  (secondary text)
    14→ *   --accent: #0f6fec (links / accent)
    15→ *   --font-body: ui-serif, Georgia, serif
    16→ *   --font-ui:   ui-sans-serif, system-ui, sans-serif
    17→ */
    18→
    19→/* ── Custom element resets ── */
    20→document, header, name, contact,
    21→email, phone, location, linkedin, website,
    22→summary, experience, role, title, company, period,
    23→bullets, bullet, education, degree, school, year, note,
    24→skills, certifications, projects, volunteer {
    25→  display: block;
    26→  margin: 0;
    27→  padding: 0;
    28→}
    29→
    30→/* ── Wrapper applied to the rendered content via .document-render ── */
    31→.document-render {
    32→  font-family: ui-serif, Georgia, "Times New Roman", Times, serif;
    33→  font-size: 16px;
    34→  line-height: 1.6;
    35→  color: #111;
    36→  background: #fff;
    37→}
    38→
    39→/* ── document root ── */
    40→.document-render document {
    41→  max-width: 720px;
    42→  margin: 0 auto;
    43→  padding: 2rem 1rem;
    44→  background: #fff;
    45→}
    46→
    47→/* ── header block ── */
    48→.document-render header {
    49→  border-bottom: 2px solid #111;
    50→  padding-bottom: 1rem;
    51→  margin-bottom: 1.5rem;
    52→}
    53→
    54→/* ── applicant name ── */
    55→.document-render name {
    56→  font-family: ui-sans-serif, system-ui, -apple-system, sans-serif;
    57→  font-size: clamp(1.4rem, 2vw + 1rem, 2rem);
    58→  font-weight: 600;
    59→  line-height: 1.2;
    60→  margin-bottom: 0.5rem;
    61→}
    62→
    63→/* ── contact row ── */
    64→.document-render contact {
    65→  display: flex;
    66→  flex-wrap: wrap;
    67→  gap: 0.25rem 1rem;
    68→  font-family: ui-sans-serif, system-ui, -apple-system, sans-serif;
    69→  font-size: 0.9rem;
    70→  color: #555;
    71→}
    72→
    73→.document-render email,
    74→.document-render phone,
    75→.document-render location,
    76→.document-render linkedin,
    77→.document-render website {
    78→  display: inline;
    79→}
    80→
    81→/* ── section labels via pseudo-elements ── */
    82→.document-render summary::before,
    83→.document-render experience::before,
    84→.document-render education::before,
    85→.document-render skills::before,
    86→.document-render certifications::before,
    87→.document-render projects::before,
    88→.document-render volunteer::before {
    89→  display: block;
    90→  font-family: ui-sans-serif, system-ui, -apple-system, sans-serif;
    91→  font-size: 0.7rem;
    92→  font-weight: 700;
    93→  letter-spacing: 0.12em;
    94→  text-transform: uppercase;
    95→  color: #555;
    96→  border-bottom: 1px solid #ddd;
    97→  padding-bottom: 0.2rem;
    98→  margin-bottom: 0.75rem;
    99→}
   100→
   101→.document-render summary::before    { content: "Summary"; }
   102→.document-render experience::before { content: "Experience"; }
   103→.document-render education::before  { content: "Education"; }
   104→.document-render skills::before     { content: "Skills"; }
   105→.document-render certifications::before { content: "Certifications"; }
   106→.document-render projects::before   { content: "Projects"; }
   107→.document-render volunteer::before  { content: "Volunteer"; }
   108→
   109→/* ── section spacing ── */
   110→.document-render summary,
   111→.document-render experience,
   112→.document-render education,
   113→.document-render skills,
   114→.document-render certifications,
   115→.document-render projects,
   116→.document-render volunteer {
   117→  margin-bottom: 1.5rem;
   118→}
   119→
   120→/* ── summary paragraph text ── */
   121→.document-render summary {
   122→  color: #111;
   123→}
   124→
   125→/* ── experience roles ── */
   126→.document-render role {
   127→  margin-bottom: 1.25rem;
   128→}
   129→
   130→.document-render role:last-child {
   131→  margin-bottom: 0;
   132→}
   133→
   134→.document-render title {
   135→  font-family: ui-sans-serif, system-ui, -apple-system, sans-serif;
   136→  font-weight: 600;
   137→  font-size: 0.95rem;
   138→  color: #111;
   139→}
   140→
   141→.document-render company {
   142→  font-family: ui-sans-serif, system-ui, -apple-system, sans-serif;
   143→  color: #555;
   144→  font-size: 0.9rem;
   145→}
   146→
   147→.document-render period {
   148→  font-family: ui-sans-serif, system-ui, -apple-system, sans-serif;
   149→  color: #777;
   150→  font-size: 0.85rem;
   151→  margin-bottom: 0.4rem;
   152→}
   153→
   154→/* ── bullets list ── */
   155→.document-render bullets {
   156→  padding-left: 1.5rem;
   157→  margin-top: 0.4rem;
   158→}
   159→
   160→.document-render bullet {
   161→  display: list-item;
   162→  list-style-type: disc;
   163→  color: #111;
   164→  margin-bottom: 0.2rem;
   165→  line-height: 1.5;
   166→}
   167→
   168→/* ── education ── */
   169→.document-render degree {
   170→  font-weight: 600;
   171→  font-size: 0.95rem;
   172→  color: #111;
   173→  font-family: ui-sans-serif, system-ui, -apple-system, sans-serif;
   174→}
   175→
   176→.document-render school,
   177→.document-render year,
   178→.document-render note {
   179→  color: #555;
   180→  font-family: ui-sans-serif, system-ui, -apple-system, sans-serif;
   181→  font-size: 0.9rem;
   182→}
   183→
   184→/* ── flat text sections ── */
   185→.document-render skills,
   186→.document-render certifications,
   187→.document-render projects,
   188→.document-render volunteer {
   189→  color: #111;
   190→  line-height: 1.7;
   191→}
   192→
   193→/* ── Print ── */
   194→@media print {
   195→  .document-render document {
   196→    padding: 0;
   197→    max-width: none;
   198→    margin: 0;
   199→  }
   200→
   201→  .document-render role,
   202→  .document-render education {
   203→    page-break-inside: avoid;
   204→    break-inside: avoid;
   205→  }
   206→}
   207→
   208→/* ── Responsive ── */
   209→@media screen and (max-width: 768px) {
   210→  .document-render document {
   211→    padding: 1rem 0.75rem;
   212→  }
   213→
   214→  .document-render name {
   215→    font-size: 1.5rem;
   216→  }
   217→
   218→  .document-render contact {
   219→    flex-direction: column;
   220→    gap: 0.15rem;
   221→  }
   222→}
